import React, { useMemo } from 'react';
import { graphql, useStaticQuery } from 'gatsby';
import { makeStyles } from '@material-ui/core/styles';
import Image from 'gatsby-image';
import classNames from 'classnames';
import { useIntl } from 'gatsby-plugin-intl';
import { Grid, Hidden, Typography } from '@material-ui/core';
import getProjects from '../data/projects';

const useStyles = makeStyles((theme) => ({
    projectPageWrapper: {
        '& a': {
            color: '#8da4f7',
        },
        '& a:visited': {
            color: '#48578a',
        },
    },
    projectWrapper: {
        padding: '15px 0',
        width: '100%',
        display: 'flex',
        borderBottom: '1px solid #494949',
        '&:last-child': {
            borderBottom: 'none',
        },
        [theme.breakpoints.down('xs')]: {
            display: 'block',
        },
    },
    projectCardWrapper: {
        // TODO
    },
    projectImageWrapper: {
        minWidth: '300px',
    },
    projectDescription: {
        padding: '0 10px',
        width: '100%',
        [theme.breakpoints.down('xs')]: {
            padding: '0',
        },
    },
    projectImage: {
        border: '1px solid #dddddd',
        [theme.breakpoints.down('xs')]: {
            width: '100% !important',
            height: '200px !important',
        },
    },
    projectLink: {
        // TODO
    },
}));

const ProjectsList = ({ quantity, className = null }) => {
    const data = useStaticQuery(graphql`
        query ProjectsListQuery {
            contractBuilder: file(
                absolutePath: { regex: "/contract-builder.png/" }
            ) {
                childImageSharp {
                    fixed(width: 300, height: 300) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            resumeBuilder: file(
                absolutePath: { regex: "/resume-builder.png/" }
            ) {
                childImageSharp {
                    fixed(width: 300, height: 300) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            magentoChatbot: file(
                absolutePath: { regex: "/magento-chatbot.png/" }
            ) {
                childImageSharp {
                    fixed(width: 300, height: 300) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            gatsbyMaterialUiBlog: file(
                absolutePath: { regex: "/gatsby-mui-blog.png/" }
            ) {
                childImageSharp {
                    fixed(width: 300, height: 300) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            jamStackSortner: file(
                absolutePath: { regex: "/jam-stack-shortener.jpg/" }
            ) {
                childImageSharp {
                    fixed(width: 300, height: 300) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            gotinha: file(
                absolutePath: { regex: "/gotinha.jpg/" }
            ) {
                childImageSharp {
                    fixed(width: 300, height: 300) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
        }
    `);

    const classes = useStyles();
    const intl = useIntl();
    let projectsData = useMemo(
        () => getProjects(Object.values(data)), [data]
    );

    if (quantity) {
        projectsData = projectsData.slice(0, quantity);
    }

    return (
        <Grid
            container
            spacing={3}
            className={classNames(className, classes.projectPageWrapper)}
        >
            {projectsData.map((elem, index) => (
                <div
                    className={classes.projectWrapper}
                    key={elem.url}
                >
                    <Grid
                        className={classes.projectImageWrapper}
                        item
                    >
                        <Hidden smUp>
                            <Typography
                                color="textPrimary"
                                variant="h5"
                            >
                                {elem.title}
                            </Typography>
                        </Hidden>
                        <a
                            className={classes.projectLink}
                            href={elem.url}
                            rel="noreferrer"
                            target="_blank"
                        >
                            <Image
                                className={classes.projectImage}
                                fixed={{
                                    ...elem.img.childImageSharp.fixed,
                                    aspectRatio: 1,
                                }}
                            />
                        </a>
                    </Grid>
                    <Grid
                        item
                        className={classes.projectDescription}
                    >
                        <Hidden xsDown>
                            <Typography
                                color="textPrimary"
                                variant="h5"
                            >
                                {elem.title}
                            </Typography>
                        </Hidden>
                        <Typography
                            color="textPrimary"
                            variant="body1"
                        >
                            {intl.formatMessage({ id: elem.description })}
                        </Typography>
                        <a
                            className={classes.projectLink}
                            href={elem.url}
                            rel="noreferrer"
                            target="_blank"
                            title={elem.title}
                        >
                            {intl.formatMessage({ id: 'check_it_out' })}
                        </a>
                    </Grid>
                </div>
            ))}
        </Grid>
    );
};

export default ProjectsList;
