import React, { useMemo } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { graphql } from 'gatsby';
import { Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import SEO from '../components/SEO';
import Layout from '../components/Layout';
import ProjectsList from '../components/ProjectsList';

const useStyles = makeStyles((theme) => ({
    projectsText: {
        margin: '15px 0',
    },
    projectsListWrapper: {
        marginLeft: '0',
        padding: '15px 25px 15px 0',
    },
    projectsWrapper: {
        marginLeft: '5px',
    },
}));

const ProjectsPage = ({ data, location, pageContext }) => {
    const intl = useIntl();
    const classes = useStyles();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'projects_page.title' })}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.personal_projects' }),
                    intl.formatMessage({ id: 'seo_keywords.games' }),
                    intl.formatMessage({ id: 'seo_keywords.development' }),
                    intl.formatMessage({ id: 'seo_keywords.es6' }),
                    intl.formatMessage({ id: 'seo_keywords.javascript' }),
                    intl.formatMessage({ id: 'seo_keywords.developer' }),
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <Typography
                className={classes.projectsText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: 'projects_page.title' })}
            </Typography>
            <div className={classes.projectsWrapper}>
                <Typography
                    color="textPrimary"
                    variant="body1"
                >
                    {intl.formatMessage({ id: 'projects_page.description' })}
                </Typography>
                <ProjectsList
                    className={classes.projectsListWrapper}
                />
            </div>
        </Layout>
    );
};

export default ProjectsPage;

export const pageQuery = graphql`
    query {
        site {
            siteMetadata {
                siteUrl
            }
        }
    }
`;
